/* {{pp-template}} */
@media (min-width: 720px) {
	.columns-start .column {
		/* @noflip */
		float: left;
		min-width: 20em;
	}

	.columns-2 .column {
		width: 50%;
	}

	.columns-3 .column {
		width: 33.3%;
	}

	.columns-4 .column {
		width: 25%;
	}

	.columns-5 .column {
		width: 20%;
	}
}

